const fs = require('node:fs');
const path = require('node:path');

const rootDir = path.resolve(__dirname, '..');
const postsDir = path.join(rootDir, 'posts');
const outputPath = path.join(rootDir, 'js', 'post-manifest.js');

const postIds = fs
  .readdirSync(postsDir, { withFileTypes: true })
  .filter((entry) => entry.isFile() && path.extname(entry.name).toLowerCase() === '.md')
  .map((entry) => path.parse(entry.name).name)
  .sort((left, right) => left.localeCompare(right, 'en', { sensitivity: 'base' }));

const output = [
  '// Generated by scripts/generate-post-manifest.js.',
  '// Add or rename files in posts/, then rerun `node scripts/generate-post-manifest.js`.',
  `window.POST_MANIFEST = ${JSON.stringify(postIds, null, 2)};`,
  '',
].join('\n');

fs.writeFileSync(outputPath, output, 'utf8');
